local function respond(status, data, message)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json"
    
    local response = {
        success = status == ngx.HTTP_OK,
        data = data,
        message = message
    }
    
    ngx.say(cjson.encode(response))
    ngx.exit(status)
end

local function authenticate()
    local auth_header = ngx.var.http_authorization
    local api_key = ngx.var.http_x_api_key
    
    if auth_header then
        local _, _, key = string.find(auth_header, "Bearer%s+(.+)")
        if key == API_KEY then
