local function sanitize_command(cmd)
    if not cmd or type(cmd) ~= "string" then
        return nil, "Invalid command"
    end
    
    cmd = string.upper(string.gsub(cmd, "^%s*(.-)%s*$", "%1"))
    
    if BLACKLISTED_COMMANDS[cmd] then
        return nil, "Command is blacklisted for security reasons"
    end
    
    if not ALLOWED_COMMANDS[cmd] then
