    return cmd
end

local function sanitize_args(args)
    if not args then
        return {}
    end
    
    if type(args) == "string" then
        return {args}
    end
    
    if type(args) ~= "table" then
        return nil, "Invalid arguments format"
    end
    
    local sanitized = {}
    for i, arg in ipairs(args) do
        if type(arg) == "string" or type(arg) == "number" then
            table.insert(sanitized, tostring(arg))
        else
            return nil, "Invalid argument type at position " .. i
        end
    end
    
    return sanitized
end

local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)
    
    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown error")
    end
    
    if REDIS_PASSWORD then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Redis authentication failed: " .. (err or "unknown error")
        end
    end
    
    return red
end

local function execute_command(red, command, args)
    local cmd_lower = string.lower(command)
    
    local func = red[cmd_lower]
    if not func then
        return nil, "Command function not found"
    end
    
    local result, err
    if #args == 0 then
        result, err = func(red)
    else
        result, err = func(red, unpack(args))
    end
    
    if not result then
        return nil, "Redis command failed: " .. (err or "unknown error")
    end
    
    return result
end

local function close_redis(red)
    if not red then
